import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"169. Overtime","description":"","frontmatter":{"title":"169. Overtime","eba":"Mental Health Services 2024-2028","topics":["hours","overtime","wages","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/169-overtime.md","filePath":"ebas/mental-health/support-services/preliminary/169-overtime.md"}'),s={name:"ebas/mental-health/support-services/preliminary/169-overtime.md"};function n(i,e,l,h,p,d){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_169-overtime" tabindex="-1">169. Overtime <a class="header-anchor" href="#_169-overtime" aria-label="Permalink to &quot;169. Overtime&quot;">​</a></h1><p><strong>169.1</strong> Where an Employee is required to work reasonable additional hours, they shall be entitled to payment of overtime in accordance with the provisions of this clause.</p><p><strong>169.2</strong> Only authorised overtime shall be paid for, and the following rates of overtime shall apply.</p><p><strong>169.3</strong> Employees shall be paid at the rate of:</p><p><strong>169.4</strong> time and one half for the first two hours and double time thereafter for hours worked in excess of the number of hours fixed as a day’s, week’s or a fortnight’s work, as the case may be</p><p><strong>169.5</strong> double time for overtime outside a spread of 12 hours from the commencement of the last previous rostered period of duty, provided that the overtime is not continuous with the next succeeding period of duty</p><p><strong>169.6</strong> time and one half for overtime outside a spread of 9hours from the time of commencing work by an Employee rostered to work broken shifts; and</p><p><strong>169.7</strong> double time for overtime outside a spread of 12 hours from the time of commencing work by an Employee rostered to work broken shifts.</p><p><strong>169.8</strong> Overtime shall be so arranged that, where reasonably practicable, the Employee who performs overtime shall have 10 consecutive hours off duty between the work of successive periods of duty.</p><p><strong>169.9</strong> In addition to clause 169.4 above, an Employee, other than a casual, who works so much overtime between the end of their agreed ordinary hours of duty and the start of their next succeeding period of duty that they would not have a 10-hour break between those times, shall be released after completion of such overtime worked until they have had a 10-hour break, without loss of pay for ordinary hours occurring during such absence.</p><p><strong>169.10</strong> If on the instructions of the Employer such an Employee resumes or continues work without having had ten consecutive hours off duty the Employee shall be paid at the rate of double time until they are released from duty for such rest period and the Employee shall then be entitled to be absent until they have had ten consecutive hours off duty without loss of pay for rostered ordinary hours occurring during such absence.</p><p><strong>169.11</strong> In the event of any Employee finishing any period of overtime at a time when reasonable means of transport are not available for the Employee to return to their place of residence the Employer shall provide adequate transport free of cost to the Employee.</p><p><strong>169.12</strong> For the purposes of this clause, in accruing or calculating payment of overtime, each period of overtime shall stand alone.</p><p><strong>169.13</strong> Transport following overtime</p><p><strong>(a)</strong> Where an Employee finishes a period of overtime at a time when reasonable means of transport are not available for the Employee to return to their place of residence the Employer will provide adequate transport free of cost to the Employee.</p><p><strong>(b)</strong> Where overtime is a result of a double shift, the provisions at subclause 169.14 below (Additional Provisions for Double Shifts) also apply.</p><p><strong>169.14</strong> Additional Provisions for Double Shifts If an Employee works a double shift (which should only occur in emergency circumstances) the following will apply to mitigate the risk of fatigue and clinical error:</p><p><strong>(a)</strong> allow breaks of at least 10 minutes’ duration in each two hours worked; and</p><p><strong>(b)</strong> adequate transport will be provided free of cost to the Employee, including the return journey where the Employee’s vehicle remains at the workplace.</p><p>Plain language terms: OT, extra hours, time and a half, double time, additional hours.</p>',20)])])}const f=o(s,[["render",n]]);export{m as __pageData,f as default};
